UPDATE esg.tb_training_plan_subject_courses
   SET courses_nm = #{coursesNm},
       remark = #{remark},
       ord_seq = #{ordSeq},
       use_yn = #{useYn}
 WHERE comp_id = #{compId}
   AND courses_id = #{coursesId}

UPDATE esg.tb_training_plan_training_center
   SET center_nm = #{centerNm},
       remark = #{remark},
       ord_seq = #{ordSeq},
       use_yn = #{useYn}
 WHERE comp_id = #{compId}
   AND center_id = #{centerId}

UPDATE esg.tb_training_plan_instructor
SET instructor_nm = #{instructorNm},
remark = #{remark},
ord_seq = #{ordSeq},
use_yn = #{useYn}
WHERE comp_id = #{compId}
AND instructor_id = #{instructorId}

